#include <systemc.h>
#include <iostream>
#include <fstream>
#include <vector>
#include <iomanip>

#include "ActUnit.h" // Your modified ActUnit header

// Helper to load raw binary files generated by the Python script
template <typename T>
void load_bin(const char* filename, std::vector<T>& buffer, size_t size) {
    std::ifstream file(filename, std::ios::binary);
    if (!file) {
        std::cerr << "Error: Could not open " << filename << std::endl;
        sc_stop();
        return;
    }
    buffer.resize(size);
    file.read(reinterpret_cast<char*>(buffer.data()), size * sizeof(T));
    file.close();
}

SC_MODULE(Testbench) {
    // Signals
    sc_clock clk;
    sc_signal<bool> rst;
    
    Connections::Combinational<bool> start_ch;
    Connections::Combinational<spec::ActVectorType> act_port_ch;
    Connections::Combinational<spec::Axi::SubordinateToRVA::Write> rva_in_ch;
    Connections::Combinational<spec::Axi::SubordinateToRVA::Read> rva_out_ch;
    Connections::Combinational<spec::StreamType> output_port_ch;
    Connections::Combinational<bool> done_ch;

    // The Module Under Test
    ActUnit dut;

    SC_CTOR(Testbench) : 
        clk("clk", 1, SC_NS), 
        dut("dut") 
    {
        // Wire up the DUT
        dut.clk(clk);
        dut.rst(rst);
        dut.start(start_ch);
        dut.act_port(act_port_ch);
        dut.rva_in(rva_in_ch);
        dut.rva_out(rva_out_ch);
        dut.output_port(output_port_ch);
        dut.done(done_ch);

        SC_THREAD(run_test);
    }

    void run_test() {
        // 1. Load Python Tensors (Size: 208 tokens * 384 channels)
        // Since kVectorSize = 16, we process 1 vector (16 elements) at a time.
        // For a single test, let's just process the first vector (16 elements) to keep it simple.
        const int num_elements = 16; 
        std::vector<int8_t> x_tok, norm2_alpha, golden_out;
        std::vector<int16_t> norm2_beta;
        
        load_bin<int8_t>("../../../../../software/tb_data/hw_in_x_tok.bin", x_tok, num_elements);
        load_bin<int8_t>("../../../../../software/tb_data/hw_w_norm2_alpha.bin", norm2_alpha, num_elements);
        load_bin<int16_t>("../../../../../software/tb_data/hw_w_norm2_beta.bin", norm2_beta, num_elements);
        load_bin<int8_t>("../../../../../software/tb_data/golden_1_norm2.bin", golden_out, num_elements);

        // Reset Sequence
        rst.write(true);
        wait(10, SC_NS);
        rst.write(false);
        wait(10, SC_NS);

        // 2. Program the ActUnit Config via RVA (AXI Write)
        // Opcode format from ActUnit.h: [OP (4)] [A2 (2)] [A1 (2)]
        // Register map: A1=1 (Alpha/Beta), A2=2 (Activations)
        std::vector<NVUINT8> instructions = {
            0x31, // INPE port -> reg 1 (Load Alpha)
            0x32, // INPE port -> reg 2 (Load X_tok)
            0x92, // EMUL reg 1, reg 2 -> reg 2 (Wait! Opcode 0x9 is EMUL. 9 = 1001. A2=2, A1=1. 1001_10_01 = 0x99)
                  // Let's use exact opcodes: OP=0x3, A2=1, A1=0 -> 0x34
        };
        
        // --- Correct Microcode Sequence ---
        // OP=3(INPE), A2=1 -> 0x34 (Load Alpha to Reg 1)
        // OP=3(INPE), A2=2 -> 0x38 (Load X_tok to Reg 2)
        // OP=9(EMUL), A2=2, A1=1 -> 0x99 (Reg2 = Reg2 * Reg1)
        // OP=3(INPE), A2=1 -> 0x34 (Load Beta to Reg 1)
        // OP=8(EADD), A2=2, A1=1 -> 0x89 (Reg2 = Reg2 + Reg1)
        // OP=4(OUTGB), A2=2 -> 0x48 (Push Reg 2 to output)
        
        NVUINT8 microcode[] = {0x34, 0x38, 0x99, 0x34, 0x89, 0x48};
        
        for(int i = 0; i < 6; i++) {
            spec::Axi::SubordinateToRVA::Write axi_cmd;
            axi_cmd.rw = 1;
            axi_cmd.addr = 0x80000 | i; // 0x8 is ActConfig region
            axi_cmd.data = microcode[i];
            rva_in_ch.Push(axi_cmd);
            wait(1, SC_NS);
        }

        // Set instruction limits and start bit in config
        spec::Axi::SubordinateToRVA::Write config_cmd;
        config_cmd.rw = 1;
        config_cmd.addr = 0x80000 | 16; // Assuming index 16 holds valid/limits
        config_cmd.data = 0x01; // Enable
        rva_in_ch.Push(config_cmd);
        wait(1, SC_NS);

        // Send Start signal
        start_ch.Push(true);
        wait(1, SC_NS);

        // 3. Stream Data in order of the INPE instructions
        spec::ActVectorType vec_alpha, vec_x, vec_beta;
        for(int i=0; i<16; i++) {
            vec_alpha[i] = norm2_alpha[i];
            vec_x[i]     = x_tok[i];
            vec_beta[i]  = norm2_beta[i];
        }

        act_port_ch.Push(vec_alpha); wait(1, SC_NS);
        act_port_ch.Push(vec_x);     wait(1, SC_NS);
        act_port_ch.Push(vec_beta);  wait(1, SC_NS);

        // 4. Capture Output and Compare
        spec::StreamType hw_result;
        while (!output_port_ch.PopNB(hw_result)) {
            wait(1, SC_NS); // Wait for processing
        }

        int errors = 0;
        std::cout << "\n--- ActUnit Affine Norm Test ---" << std::endl;
        for(int i=0; i<16; i++) {
            int hw_val = hw_result.data[i].to_int();
            int g_val = golden_out[i];
            
            if (hw_val != g_val) {
                std::cout << "Mismatch at [" << i << "]: HW=" << hw_val << " | Golden=" << g_val << std::endl;
                errors++;
            }
        }

        if (errors == 0) {
            std::cout << "SUCCESS: ActUnit EMUL and EADD perfectly match Python Golden Output!" << std::endl;
        } else {
            std::cout << "FAILED with " << errors << " errors." << std::endl;
        }

        sc_stop();
    }
};

int sc_main(int argc, char *argv[]) {
    Testbench tb("tb");
    sc_start();
    return 0;
}